#include <iostream>
using namespace std;

class Base {
public:
 // Base declares function as virtual
 virtual void display() {
 cout << "Base::display() called" << endl;
 }
 virtual ~Base() { } // Virtual destructor
};

class Derived : public Base {
public:
 // Virtual attribute automatically inherited!
 // No need to specify 'virtual' keyword again
 void display() override {
 cout << "Derived::display() called" << endl;
 }
};

class MoreDerived : public Derived {
public:
 // Virtual attribute continues to be inherited
 void display() {
 cout << "MoreDerived::display() called" << endl;
 }
};

int main() {
 Base* ptr;
 Derived d;
 MoreDerived md;

 ptr = &d;
 ptr->display(); // Runtime: calls Derived::display()

 ptr = &md;
 ptr->display(); // Runtime: calls MoreDerived::display()

 return 0;
}

#include <iostream>
using namespace std;

// Abstract class with pure virtual function
class Shape {
public:
 // Pure virtual function - makes Shape abstract
 virtual void draw() = 0;

 // Virtual destructor for proper cleanup
 virtual ~Shape() { }
};

class Circle : public Shape {
public:
 void draw() override {
 cout << "Drawing Circle" << endl;
 }
};

class Rectangle : public Shape {
public:
 void draw() override {
 cout << "Drawing Rectangle" << endl;
 }
};

int main() {
 // Shape s; // ERROR: Cannot create object of abstract class

 Shape* shapes[2];
 shapes[0] = new Circle();
 shapes[1] = new Rectangle();

 for(int i = 0; i < 2; i++) {
 shapes[i]->draw(); // Polymorphic calls
 }

 for(int i = 0; i < 2; i++) {
 delete shapes[i];
 }

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 // Virtual destructor - important for polymorphism
 virtual ~Base() {
 cout << "Base destructor called" << endl;
 }
 virtual void show() {
 cout << "Base::show()" << endl;
 }
};

class Derived : public Base {
private:
 int* data;
public:
 Derived() {
 data = new int[100]; // Dynamic allocation
 cout << "Derived constructor: allocated memory" << endl;
 }

 ~Derived() override {
 delete[] data; // Cleanup derived resources
 cout << "Derived destructor called: memory freed" << endl;
 }

 void show() override {
 cout << "Derived::show()" << endl;
 }
};

int main() {
 Base* ptr = new Derived();
 ptr->show(); // Polymorphic call
 delete ptr; // Without virtual destructor, only Base destructor called!

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 int baseData;
 virtual void show() {
 cout << "Base::show() - baseData: " << baseData << endl;
 }
};

class Derived : public Base {
public:
 int derivedData;
 void show() override {
 cout << "Derived::show() - baseData: " << baseData 
 << ", derivedData: " << derivedData << endl;
 }
};

int main() {
 Derived d;
 d.baseData = 10;
 d.derivedData = 20;

 // PROBLEM: Slicing - derived part is sliced off
 Base b = d; // Slicing happens here!
 b.show(); // Calls Base::show(), not Derived::show()

 cout << "--- Using pointer (no slicing) ---" << endl;

 // SOLUTION: Use pointer
 Base* ptr = &d;
 ptr->show(); // Correctly calls Derived::show()

 cout << "--- Using reference (no slicing) ---" << endl;

 // SOLUTION: Use reference
 Base& ref = d;
 ref.show(); // Correctly calls Derived::show()

 return 0;
}

#include <iostream>
using namespace std;

class Base {
public:
 virtual void process() {
 cout << "Base::process()" << endl;
 }
 virtual void finalMethod() final {
 cout << "Base::finalMethod() - cannot override" << endl;
 }
};

class Derived : public Base {
public:
 // Correct override - compiler checks matching signature
 void process() override {
 cout << "Derived::process()" << endl;
 }

 // ERROR: Cannot override final method
 // void finalMethod() override { } // Compiler error!

 void extraMethod() {
 cout << "Derived::extraMethod()" << endl;
 }
};

class MoreDerived : public Derived {
public:
 // Still virtual - can override again
 void process() override {
 cout << "MoreDerived::process()" << endl;
 }

 // ERROR: finalMethod was marked final in Base
 // void finalMethod() { } // Compiler error!
};

int main() {
 Base* ptr = new MoreDerived();
 ptr->process(); // Calls MoreDerived::process()
 ptr->finalMethod(); // Calls Base::finalMethod()

 delete ptr;
 return 0;
}
